#include<stdio.h>
int main() {
	long long int i=0,j=0,k,l,n,m,a[100]={0},b[100]={0};
	scanf("%lld %lld",&n,&m);
	if(n==1 && m==1)
		printf("0\n");
	else {
		while(n) {
			a[i] = n%2;
			n /= 2;
			i++;
		}
		while(m) {
			b[j] = m%2;
			m /= 2;
			j++;
		}
		i=65;
		m=1;
		while(a[i]==b[i] && i+1)
			i--;
		for(j=0;j<i+1;j++,m*=2);
		printf("%lld\n",m-1);
	}
	return 0;
}

